"""Build the synthetic Apple Podcasts SQLite fixture.

Run manually: python tests/fixtures/_build_apple_podcasts_fixture.py
"""
import sqlite3
from pathlib import Path

OUT = Path(__file__).parent / "apple_podcasts_mtlibrary.sqlite"
if OUT.exists():
    OUT.unlink()

conn = sqlite3.connect(str(OUT))
conn.executescript("""
CREATE TABLE ZMTPODCAST (Z_PK INTEGER PRIMARY KEY, ZTITLE TEXT);
CREATE TABLE ZMTEPISODE (
    Z_PK INTEGER PRIMARY KEY,
    ZTITLE TEXT, ZCLEANEDTITLE TEXT,
    ZPODCAST INTEGER REFERENCES ZMTPODCAST(Z_PK),
    ZUUID TEXT, ZGUID TEXT, ZENCLOSUREURL TEXT,
    ZDURATION REAL, ZPLAYHEAD REAL,
    ZPLAYSTATE INTEGER, ZHASBEENPLAYED INTEGER,
    ZPLAYCOUNT INTEGER, ZMARKASPLAYED INTEGER,
    ZPLAYSTATEMANUALLYSET INTEGER, ZPLAYSTATESOURCE INTEGER,
    ZLASTDATEPLAYED REAL, ZLASTUSERMARKEDASPLAYEDDATE REAL,
    ZPLAYSTATELASTMODIFIEDDATE REAL,
    ZPUBDATE REAL, ZIMPORTDATE REAL, ZDOWNLOADDATE REAL
);
INSERT INTO ZMTPODCAST VALUES (1, 'Reply All');
INSERT INTO ZMTPODCAST VALUES (2, 'Hard Fork');
-- Real Apple Podcasts: after completion, ZPLAYSTATE goes back to 0,
-- ZHASBEENPLAYED is NULL, ZPLAYHEAD resets to 0. The only durable
-- completion signal is ZPLAYCOUNT > 0.
-- ep 10: single completion, played once
INSERT INTO ZMTEPISODE (Z_PK, ZTITLE, ZCLEANEDTITLE, ZPODCAST, ZUUID, ZDURATION, ZPLAYHEAD, ZPLAYSTATE, ZHASBEENPLAYED, ZPLAYCOUNT, ZPLAYSTATEMANUALLYSET, ZLASTDATEPLAYED)
    VALUES (10, 'The Crime Machine, Part I', 'The Crime Machine, Part I', 1, 'ep-uuid-10', 2700.0, 0.0, 0, NULL, 1, 0, 769876200.0);
-- ep 11: replayed twice (ZPLAYCOUNT=3 — first listen + two replays)
INSERT INTO ZMTEPISODE (Z_PK, ZTITLE, ZCLEANEDTITLE, ZPODCAST, ZUUID, ZDURATION, ZPLAYHEAD, ZPLAYSTATE, ZHASBEENPLAYED, ZPLAYCOUNT, ZPLAYSTATEMANUALLYSET, ZLASTDATEPLAYED)
    VALUES (11, 'Episode About AI', 'Episode About AI', 2, 'ep-uuid-11', 3600.0, 0.0, 0, NULL, 3, 0, 769962600.0);
-- ep 12: in-progress, never completed (ZPLAYCOUNT=0 — filtered out)
INSERT INTO ZMTEPISODE (Z_PK, ZTITLE, ZCLEANEDTITLE, ZPODCAST, ZUUID, ZDURATION, ZPLAYHEAD, ZPLAYSTATE, ZHASBEENPLAYED, ZPLAYCOUNT, ZPLAYSTATEMANUALLYSET, ZLASTDATEPLAYED)
    VALUES (12, 'In-Progress Ep', 'In-Progress Ep', 1, 'ep-uuid-12', 3000.0, 1500.0, 2, 0, 0, 0, 769876200.0);
-- ep 13: manually marked played (ZPLAYSTATEMANUALLYSET=1 — filtered out)
INSERT INTO ZMTEPISODE (Z_PK, ZTITLE, ZCLEANEDTITLE, ZPODCAST, ZUUID, ZDURATION, ZPLAYHEAD, ZPLAYSTATE, ZHASBEENPLAYED, ZPLAYCOUNT, ZPLAYSTATEMANUALLYSET, ZLASTDATEPLAYED)
    VALUES (13, 'Marked Played', 'Marked Played', 2, 'ep-uuid-13', 1800.0, 0.0, 0, NULL, 1, 1, 769876200.0);
""")
conn.commit()
conn.close()
print(f"wrote {OUT}")
